	(108, 'Executive– Business Development', 'Park Control & Communication', '', 'Full-time', 'Bangalore', 'On-site', NULL, '4 years+', '"Sales/ Marketing"', 'The Executive – Business Development will be responsible for front-end sales and strategic marketing of the company’s solutions and services. The role demands strong domain knowledge of Electronics, instrumentation, Defence systems, and embedded technologies. The candidate will be accountable for identifying business opportunities, mapping customer requirements, and driving order booking targets. This position plays a key role in enhancing the company’s profile within the Defence, Aerospace, and Satellite industry ecosystem.', NULL, '2026-02-05 09:27:52.658771+00', true, '2025-12-05 07:49:15.982366+00', '2026-01-06 09:27:52.658771+00', 'B.E. in EEE, ECE, or ECS. MBA ', 'Senior', 700000, 700000, 'open', '2025-12-05 07:49:16.505+00', NULL, '["The Executive – Business Development will be responsible for front-end sales and strategic marketing of the company’s solutions and services. The role demands strong domain knowledge of Electronics, instrumentation, Defence systems, and embedded technologies. The candidate will be accountable for identifying business opportunities, mapping customer requirements, and driving order booking targets. This position plays a key role in enhancing the company’s profile within the Defence, Aerospace, and Satellite industry ecosystem."]', '[]', '""', 0, 0, 0, '902d03ef-71c0-4781-8e09-c2ef46511cbb', 'Executive– Business Development', '902d03ef-71c0-4781-8e09-c2ef46511cbb', '[0.004234162,-0.040944725,0.01588173,-0.012531497,-0.02069262,0.035890393,0.002802488,0.053418256,-0.018768264,0.03489344,0.054021068,-0.047992967,-0.0037385826,-0.035357136,0.067051046,0.038000226,-0.017226461,-0.026361354,-0.023370488,0.04667142,0.037745193,0.023950113,0.01555714,0.010821602,0.0068917437,0.0019069669,-0.018652339,0.022582198,0.013922597,-0.006486006,0.08003464,-0.015394845,-0.026175873,0.01398056,-0