	(168, 'Frontend Engineer (React)', 'Rareminds Technologies Pvt Ltd', '', 'Full-time', 'Bangalore, India', 'On-site', NULL, '2–4 years', '"React, TypeScript, JavaScript, REST APIs, HTML, CSS"', 'We are looking for a skilled Frontend Engineer to build responsive and scalable web applications. The role involves collaborating with designers and backend engineers to deliver high-quality user experiences for enterprise products.', NULL, '2025-12-19 00:00:00+00', false, '2025-12-19 09:40:50.894422+00', '2026-01-06 08:25:52.733892+00', 'Product Engineering', 'Mid', 900000, 1400000, 'draft', '2025-12-19 09:40:50.886+00', NULL, '["2+ years of experience in frontend development", "Strong knowledge of React and modern JavaScript", "Experience with RESTful APIs", "Understanding of UI/UX best practices", "Good communication skills"]', '["Develop reusable and maintainable UI components", "Collaborate with backend teams for API integration", "Optimize applications for performance and scalability", "Participate in code reviews and sprint planning", "Ensure cross-browser and device compatibility"]', '"Health insurance\nFlexible work hours\nHybrid work model\nLearning & certification budget\nPaid annual leave"', 1, 0, 0, '902d03ef-71c0-4781-8e09-c2ef46511cbb', 'Frontend Engineer (React)', '58f00857-f9b9-4008-9382-e722dd5c7992', '[0.0009844445,0.0040079392,0.021247048,0.027479671,0.0054988572,-0.0043265866,-0.037629608,0.07002054,0.010518283,0.028812727,0.0148390215,-0.043406185,-0.004174571,-0.0060162935,0.03299899,0.026684513,0.0023606205,-0.0632851,-0.015973289,0.034261886,0.006501573,-0.010208406,0.03494011,0.015330148,0.031361904,0.00786971,-0.008290675,0.05865448,0.0040576365,-0.0059870603,0.048691638,-0.02525791,-0.0037009853,0.013798303,0.035875585,0.016628124,0.038728796,-0.003993322,0.005723957,0.008752568,-0.03456592,-0.03917315,0.01032534,0.05804642,0.014078946,-0.009325548,-0.061367366,0.00950095,0.011360212,0.0018271058,-0.040178787,-0.031034486,-0.002094594,0.03482317,-