	(180, 'Full Stack Dev', 'FrontLine Corp.', 'data:image/jpeg;base64,', 'Internship', 'Bangalore', 'On-site', NULL, '3', '"React, Node ,"', 'Join FrontLine Corp as a Full Stack Developer. You will work on building and maintaining web applications using modern technologies. Responsibilities include developing frontend interfaces with React, building backend APIs with Node.js, database design and optimization, collaborating with cross-functional teams, and participating in code reviews. This is an excellent opportunity for developers who want to work on challenging projects in a fast-paced environment.', NULL, '2025-12-23 00:00:00+00', true, '2025-12-23 06:53:24.114685+00', '2026-01-08 08:34:03.334828+00', 'Frontend', 'Entry', 12345, 12343, 'open', '2025-12-23 06:53:24.744+00', NULL, '["2+ years experience in full stack development", "Proficiency in React and Node.js", "Experience with SQL and NoSQL databases", "Understanding of RESTful API design", "Good communication and teamwork skills", "Bachelor degree in Computer Science or related field"]', '[]', '"Health Insurance"', 2, 0, 1, '902d03ef-71c0-4781-8e09-c2ef46511cbb', 'Full Stack Dev', '902d03ef-71c0-4781-8e09-c2ef46511cbb', '[-0.03302176,0.00079597556,0.02543055,-0.0022824463,0.0010395551,-0.012938945,0.0028178976,0.03223553,0.012844055,0.02987683,0.033482656,-0.0352449,-0.0023502249,-0.021946728,0.03969118,0.021621391,-0.02486121,-0.03464845,-0.017636005,0.054521147,0.018313792,-0.009299231,0.03576002,-0.006083134,0.05509049,0.029714162,-0.019371139,0.052894462,0.021485833,-0.018246014,0.05509049,-0.03917606,0.020943604,0.03695292,0.06560974,0.024915433,0.07325517,0.015277308,0.04009785,-0.0049071745,-0.04229388,-0.029253267,0.038498275,0.02984972,0.00438189,0.029714162,-0.051620223,0.052054007,0.045005027,0.03454,-0.0404503,-0.029632827,0.017392002,0.007394651,-0.03022928,-0.015751759,0.016876884,0.051810004,0.010912363,0.007252316,0.018069789,-0.048746407,0.024712097,0.053545136,-0.037603598,-0.008133438,-0.02